def factorial(n):
    """Calcul de la factorielle de n"""
    if n == 0:
        return 1
    else:
        return n * factorial(n-1)

def binomial_coefficient(n, k):
    """Calcul du coefficient binomial"""
    return factorial(n) / (factorial(k) * factorial(n-k))

def somme_carrés_coefficients_binomiaux(n):
    """Calcul de la somme des carrés des coefficients binomiaux"""
    if n < 0:
        n = -n
    return binomial_coefficient(2*n, n)

