def newman_prime(n):
    # Définition d'une fonction pour vérifier si un nombre est premier
    def est_premier(num):
        if num < 2:
            return False
        for i in range(2, int(num ** 0.5) + 1):
            if num % i == 0:
                return False
        return True

    # Définition d'une fonction pour trouver les nombres premiers de la forme 2^p ± 1
    def trouve_newman_shanks_williams(p):
        return 2 ** p + 1

    # Définition d'une fonction pour trouver les nombres premiers de la forme 2^p - 1
    def trouve_newman_shanks_williams_moins_un(p):
        return 2 ** p - 1

    # Définition d'une fonction pour trouver les nombres premiers de la forme 2^p ± 1
    def trouve_newman_shanks_williams_premier(p):
        return trouve_newman_shanks_williams(p) if est_premier(trouve_newman_shanks_williams(p)) else trouve_newman_shanks_williams_moins_un(p)

    # Définition d'une fonction pour trouver les nombres premiers de la forme 2^p ± 1
