    # Vérification de base : si n est inférieur ou égal à 0, retourner 0
    if n <= 0:
        return 0
    # Vérification de base : si n est égal à 1, retourner 1
    elif n == 1:
        return 1
    # Cas général : appeler la fonction fibonacci avec n-1 et n-2
    else:
